import static be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings.KEDSPECIAALTYPE_COMPENSATOIRE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings.MANDATARIS_BAS_DBL_VAKGELD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings.MANDATARIS_ZONDER_BAS_SI_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings.ZONDER_BAS_SI_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey.BASIS_BEDRAG_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey.BRUTO_MAANDLOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey.JAARBEDRAG_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.BEGROTING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.INDEXATOR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONCODE_GEWOON_LOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONCODE_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.OPPER_LAATSTE_GEGEVENS_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PRESTATIEVERHOUDING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REGUL_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.RKM_COREHR_CONFIG_MANAGER;

public class BerekenBrutoTheoretischJaarLoon extends AbstractRekenCommand {

    private final NlpGlobalService globalService;
    private final ConstantManager constantManager;

    public BerekenBrutoTheoretischJaarLoon(ConstantManager constantManager, NlpGlobalService service) {
        this.constantManager = constantManager;
        this.globalService = service;
    }

    @Override
    protected boolean execute(RekenContext context) {
        context.put(LOONELEMENT_MANAGER_KEY, new LoonElementManagerImp());
        Persoon persoon = context.getUnchecked(PERSOON_KEY);

        Set<Opdracht> opdrachten = persoon.getOpdrachten();
        for (Opdracht opdracht : opdrachten) {
            berekenBrutoLoon(context, opdracht);
        }
        return CONTINUE_PROCESSING;
    }

    private void berekenBrutoLoon(RekenContext context, Opdracht opdracht) {
        RegulManager regulManager = context.getUnchecked(REGUL_MANAGER_KEY);
        RekenContext opdrachtContext = context.getOpdrachtContext(opdracht);
        Opper normOpper = opdrachtContext.getUnchecked(OPPER_LAATSTE_GEGEVENS_KEY);

        SleutelGegevens gegevens = new SleutelGegevensSingleOpper(normOpper);
        boolean begroting = context.getBoolean(BEGROTING_KEY);
        BigDecimal prestatieVerhouding = RkmPrestatieVerhouding.bepaalTheoretisch(gegevens, regulManager, begroting);
        opdrachtContext.putDoubleKey(PRESTATIEVERHOUDING_KEY, normOpper, prestatieVerhouding);
        RekenTijd rekenTijd = context.getUnchecked(REKENTIJD_KEY);
        RkmCoreHrConfiguratieManager rkmCoreHrConfiguratieManager = context.getUnchecked(RKM_COREHR_CONFIG_MANAGER);
        RkmCoreHrConfiguratie rkmCoreHrConfiguratie = RkmCoreHrConfiguratie.builder().build();
        if (Objects.nonNull(rkmCoreHrConfiguratieManager)) {
            rkmCoreHrConfiguratie = rkmCoreHrConfiguratieManager.getRkmCoreHrConfiguratie(opdracht, rekenTijd);
        }
        List<LoonElement> loonElementen = berekenVergoedingen(opdrachtContext, gegevens, rkmCoreHrConfiguratie, rekenTijd);
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        for (LoonElement element : loonElementen) {
            manager.addLoonElement(element, normOpper);
        }
    }

    //TODO Het grootste verschil met de 'gewone' bruto  berekening is het jaarNaarBasis stuk als we dit zouden uitsplitsen kunnen we maybe aan code herbruik doen.
    private List<LoonElement> berekenVergoedingen(RekenContext context, SleutelGegevens gegevens, RkmCoreHrConfiguratie rkmCoreHrConfiguratie, RekenTijd rekenTijd) {

        RegulManager regulManager = context.getUnchecked(REGUL_MANAGER_KEY);
        LoonCodeManager loonCodeManager = context.getUnchecked(LOONCODE_MANAGER_KEY);
        Indexator indexator = context.getUnchecked(INDEXATOR_KEY);
        List<LoonElement> loonElementen = new ArrayList<>();

        GewoonLoon gewoonLoon = GewoonLoonFactory.getGewoonLoon(loonCodeManager, rekenTijd);
        AardKodeExtensie looncodeGewoonLoon = gewoonLoon.bepaalAardKodeExtensie(gegevens);
        context.put(LOONCODE_GEWOON_LOON_KEY, looncodeGewoonLoon);
        LoonElement normaalLoon = new LoonElement(looncodeGewoonLoon);

        Money jaarLoon = gegevens.getJaarWedde();
        jaarLoon = jaarLoon.add(gegevens.getSalarisverhoging());
        normaalLoon.putProperty(JAARBEDRAG_KEY, jaarLoon);
        loonElementen.add(normaalLoon);

        LoonCodeCalculatorFactory factory = new LoonCodeCalculatorFactory(constantManager, regulManager, loonCodeManager, globalService, rkmCoreHrConfiguratie);
        MoneyMap<AardKodeExtensie> vergoedingToBedragMap = maakVergoedingToBedragMap(loonCodeManager, gegevens.getVergoedingen());
        for (AardKodeExtensie aardKodeExtensie : vergoedingToBedragMap.keySet()) {
            LoonElement element = new LoonElement(aardKodeExtensie);

            LoonCodeCalculator calculator = factory.genereerLoonCodeCalculator(gegevens, aardKodeExtensie, rekenTijd);
            Money bedrag = calculator.berekenBedrag100Percent(vergoedingToBedragMap.getMoney(aardKodeExtensie));
            element.putProperty(JAARBEDRAG_KEY, bedrag);
            loonElementen.add(element);
        }

        for (LoonElement element : loonElementen) {
            Money bedrag = element.getPropertyMoney(JAARBEDRAG_KEY);
            AardKodeExtensie loonCode = element.getAardKodeExtensie();
            bedrag = indexator.indexeer(bedrag, loonCode, gegevens);
            boolean isCompensatoire = loonCode.behoortTotGroep(KEDSPECIAALTYPE_COMPENSATOIRE_KEY);
            if (!loonCode.isForfaitair() && !isCompensatoire) {
                boolean begroting = context.getBoolean(BEGROTING_KEY);
                bedrag = jaarNaarBasis(bedrag, gegevens, regulManager, begroting);
            }
            element.putProperty(BASIS_BEDRAG_KEY, bedrag);
            element.putProperty(BRUTO_MAANDLOON_KEY, bedrag);
            Money basisRsz = bedrag;
            if (gegevens.getAfwezigheidsCode().equals(RszppoPrestatiekode.PK180.getCode())) {
                basisRsz = basisRsz.multiply(new BigDecimal("1.25"));
            }
            if (heeftBassi(loonCode, gegevens.getOpdracht().getHoedanigheid())) {
                element.putProperty(BASIS_SOCIALE_INHOUDINGEN_KEY, basisRsz);
            }
        }

        return loonElementen;
    }

    private MoneyMap<AardKodeExtensie> maakVergoedingToBedragMap(LoonCodeManager loonCodeManager, Set<Vergoeding> vergoedingen) {
        MoneyMap<AardKodeExtensie> vergoedingToBedragMap = new HashMoneyMap<>();
        for (Vergoeding vergoeding : vergoedingen) {
            AardKodeExtensie aardKodeExtensie = loonCodeManager.getByVergoeding(vergoeding);
            vergoedingToBedragMap.addToMoney(aardKodeExtensie, vergoeding.getBedragWerknemer());
        }
        return vergoedingToBedragMap;
    }

    public Money jaarNaarBasis(Money bedrag, SleutelGegevens gegevens, RegulManager regulManager, boolean begroting) {
        if (gegevens.getRekenWijze() == Rekenwijze.MAAND || gegevens.getRekenWijze() == Rekenwijze.UUR) {
            BigDecimal prestatieVerhouding = RkmPrestatieVerhouding.bepaalTheoretisch(gegevens, regulManager, begroting);
            bedrag = bedrag.multiply(prestatieVerhouding).round(2);
        }
        return bedrag;
    }

    private boolean heeftBassi(AardKodeExtensie looncode, Hoedanigheid hoedanigheid) {
        boolean heeftBassi = !looncode.behoortTotGroep(ZONDER_BAS_SI_KEY);
        if (heeftBassi && hoedanigheid == Hoedanigheid.MANDATARISSEN) {
            heeftBassi = looncode.behoortTotGroep(MANDATARIS_BAS_DBL_VAKGELD_KEY) || !looncode.behoortTotGroep(MANDATARIS_ZONDER_BAS_SI_KEY);
        }
        return heeftBassi;
    }
}
